import "@hatch:game" for Game
import "@hatch:gpu"  for Renderer2D, Camera2D, Sprite
import "@hatch:json" for JSON

// Fruit Slicer — a Fruit-Ninja-style swipe game built on
// @hatch:game + @hatch:gpu. Fruits launch from the bottom of the
// stage on a parabolic arc; click-and-drag the mouse across them
// to slice. Each cut spawns two halves that tumble with their
// own rotation and gravity. Three misses ends the run.
//
// Asset credits:
//   * Fruits asset pack by Lemon Balm — https://lemon-balm.itch.io/
//   * Heart HUD icon by Penzilla — https://penzilla.itch.io/
//
// Features:
//   * Texture atlas + JSON manifest fetched at startup via
//     Browser.fetchBytes / Browser.fetch. One Sprite reused for
//     every draw — Renderer2D batches by texture so the whole
//     frame ships in a single GPU draw call.
//   * Real 2D rotation on the halves through Sprite.rotation
//     (extension to @hatch:gpu's Renderer2D).
//   * 5×7 bitmap font baked into the atlas for the score and the
//     "GAME OVER" / "CLICK TO RESUME" overlay — no font runtime.
//   * Swipe physics: minimum length filter, halves spread
//     perpendicular to the cut direction with a follow-through
//     along the swipe.
class FruitSlicer is Game {
  construct new() {}

  config { {
    "title":      "Fruit Slicer",
    "width":      640,
    "height":     480,
    "clearColor": [0.04, 0.03, 0.08, 1.0],
    "canvas":     "stage-canvas"
  } }

  setup(g) {
    _renderer = Renderer2D.new(g.device, g.surfaceFormat)
    _camera   = Camera2D.contain(640, 480, g.width, g.height)

    // Atlas + manifest — bytes for the texture, JSON for the
    // sprite-name → UV lookup table.
    var bytes    = Browser.fetchBytes("./assets/fruit-slicer/atlas.rgba8").await
    var jsonText = Browser.fetch("./assets/fruit-slicer/atlas.json").await
    _manifest    = JSON.parse(jsonText)
    var size = _manifest["size"]
    _atlasW = size[0]
    _atlasH = size[1]

    _atlas = g.device.createTexture({
      "width":  _atlasW, "height": _atlasH,
      "format": "rgba8unorm",
      "usage":  ["texture-binding", "copy-dst"]
    })
    g.device.writeTexture(_atlas, bytes, {
      "width": _atlasW, "height": _atlasH, "bytesPerRow": _atlasW * 4
    })

    _fruitNames = []
    for (k in _manifest["sprites"].keys) _fruitNames.add(k)

    // One reusable Sprite for everything. Renderer2D batches by
    // texture, and we have one atlas, so swapping uv + position
    // per call still flushes in a single GPU draw at the end.
    _quad = Sprite.new(_atlas)
    _quad.anchor(0.5, 0.5)

    _seed = 1
    resetGame_
    System.print("Fruit Slicer ready")
  }

  resize(g, w, h) { _camera.fitContain(w, h) }

  resetGame_ {
    _fruits = []
    _halves = []
    _trail  = []
    _score  = 0
    _lives  = 3
    _state  = "playing"
    _spawnTimer = 0.5
    _gameoverT  = 0
  }

  // Park-Miller minimal-standard LCG. The product seed*16807 peaks
  // at ~3.6e13 — well under 2^53 — so it stays exact in f64 and the
  // mod keeps state in [0, 2^31-2]. The older mul-add-mask form
  // went through Wren's bitwise &, which saturates the LHS via
  // (as u32) and would emit 2^31-1 for any large product,
  // eventually pinning rand_ to 1.0.
  rand_ {
    _seed = (_seed * 16807) % 2147483647
    return _seed / 2147483647
  }
  randRange_(lo, hi) { lo + (hi - lo) * rand_ }

  update(g) {
    // Clamp dt so a tab-focus-loss gap (rAF stops while the window
    // is hidden, then Browser.nextFrame.await resumes with a
    // multi-second delta) doesn't drain every fruit past the
    // bottom edge in one tick. ~33 ms = a 30 fps step's worth.
    var dt = g.dt
    if (dt > 0.033) dt = 0.033

    // Game-over animation tick: drives the "GAME OVER" letters'
    // pulse alpha (sin-based) and lets a click reset.
    if (_state == "gameover") {
      _gameoverT = _gameoverT + dt
      if (g.input.mouseJustPressed(0)) resetGame_
    } else {
      _spawnTimer = _spawnTimer - dt
      if (_spawnTimer <= 0) {
        spawn_
        _spawnTimer = randRange_(0.7, 1.4)
      }

      // Whole-fruit kinematics + miss detection.
      var i = 0
      while (i < _fruits.count) {
        var f = _fruits[i]
        f["vy"] = f["vy"] + 1500 * dt
        f["x"]  = f["x"]  + f["vx"] * dt
        f["y"]  = f["y"]  + f["vy"] * dt
        if (f["y"] > 540) {
          _fruits.removeAt(i)
          _lives = _lives - 1
          if (_lives <= 0) {
            _state = "gameover"
            _gameoverT = 0
          }
        } else {
          i = i + 1
        }
      }
    }

    // Halves drift + age out.
    var hi = 0
    while (hi < _halves.count) {
      var h = _halves[hi]
      h["vy"] = h["vy"] + 1500 * dt
      h["x"]  = h["x"]  + h["vx"] * dt
      h["y"]  = h["y"]  + h["vy"] * dt
      h["rot"] = h["rot"] + h["vrot"] * dt
      h["age"] = h["age"] + dt
      if (h["age"] > 1.0 || h["y"] > 600) {
        _halves.removeAt(hi)
      } else {
        hi = hi + 1
      }
    }

    // Mouse trail. Buffer grows while LMB is held; on release
    // we keep the existing points but stop adding so the streak
    // fades naturally as ages tick up.
    if (g.input.mouseDown(0)) {
      var mx = g.input.mouseX * (640 / g.width)
      var my = g.input.mouseY * (480 / g.height)
      if (_trail.count > 0) {
        var p1 = _trail[_trail.count - 1]
        checkSlice_(p1["x"], p1["y"], mx, my)
        // Interpolate between the last sample and the new one so
        // a fast swipe reads as a continuous streak instead of
        // discrete dots. step controls the visual density —
        // smaller = denser, more sprites per frame.
        var dx = mx - p1["x"]
        var dy = my - p1["y"]
        var dist = (dx * dx + dy * dy).sqrt
        var step = 6
        var nSeg = (dist / step).floor
        if (nSeg > 1) {
          var i = 1
          while (i < nSeg) {
            var t = i / nSeg
            _trail.add({"x": p1["x"] + dx * t, "y": p1["y"] + dy * t, "age": 0})
            i = i + 1
          }
        }
      }
      _trail.add({"x": mx, "y": my, "age": 0})
      if (_trail.count > 64) _trail.removeAt(0)
    }
    var j = 0
    while (j < _trail.count) {
      _trail[j]["age"] = _trail[j]["age"] + 1
      if (_trail[j]["age"] > 16) {
        _trail.removeAt(j)
      } else {
        j = j + 1
      }
    }
  }

  spawn_ {
    var name = _fruitNames[(rand_ * _fruitNames.count).floor]
    _fruits.add({
      "name": name,
      "x":    randRange_(80, 560),
      "y":    520,
      "vx":   randRange_(-180, 180),
      "vy":   randRange_(-1100, -900),
    })
  }

  // Per-frame slice check. (x1,y1)→(x2,y2) is the swipe segment
  // between this frame and the previous mouse position. We require
  // a minimum length so a single click can't slice anything — the
  // swipe has to actually cut through a fruit. The cut direction
  // is the segment direction; halves fly perpendicular to it (so
  // a horizontal swipe explodes top-and-bottom, a vertical swipe
  // splits left-and-right) and pick up a small velocity component
  // along the swipe so the cut feels followed-through.
  checkSlice_(x1, y1, x2, y2) {
    var sdx = x2 - x1
    var sdy = y2 - y1
    var sLen2 = sdx * sdx + sdy * sdy
    if (sLen2 < 64) return                  // < 8px swipe = treat as click
    var sLen = sLen2.sqrt
    // Unit swipe direction + its perpendicular (rotated 90° CCW).
    var ux = sdx / sLen
    var uy = sdy / sLen
    var px = -uy
    var py =  ux
    // Cut angle for spawning halves rotated to match the swipe.
    var cutAngle = uy.atan(ux)              // atan2 result
    var i = 0
    while (i < _fruits.count) {
      var f = _fruits[i]
      var hw = 36
      var hh = 36
      var ax = f["x"] - hw
      var ay = f["y"] - hh
      var bx = f["x"] + hw
      var by = f["y"] + hh
      if (segVsAabb_(x1, y1, x2, y2, ax, ay, bx, by)) {
        // Spread the halves in opposite directions perpendicular
        // to the swipe, plus a tail along the swipe so the slice
        // visually carries the fruit's momentum.
        var spreadV  = 280   // perpendicular kick (px/s)
        var followV  =  60   // tail along the swipe
        var spin     = randRange_(8, 14)
        _halves.add({
          "name": f["name"], "side": "left",
          "x": f["x"] + px * 14,
          "y": f["y"] + py * 14,
          "vx": f["vx"] + px * spreadV + ux * followV,
          "vy": f["vy"] + py * spreadV + uy * followV - 80,
          "age": 0, "rot": cutAngle, "vrot": -spin,
        })
        _halves.add({
          "name": f["name"], "side": "right",
          "x": f["x"] - px * 14,
          "y": f["y"] - py * 14,
          "vx": f["vx"] - px * spreadV + ux * followV,
          "vy": f["vy"] - py * spreadV + uy * followV - 80,
          "age": 0, "rot": cutAngle, "vrot": spin,
        })
        _fruits.removeAt(i)
        _score = _score + 1
      } else {
        i = i + 1
      }
    }
  }

  // Segment-vs-AABB. Both endpoints inside → hit. Otherwise test
  // segment against each of the four box edges via segment-segment.
  segVsAabb_(x1, y1, x2, y2, ax, ay, bx, by) {
    if (x1 < ax && x2 < ax) return false
    if (x1 > bx && x2 > bx) return false
    if (y1 < ay && y2 < ay) return false
    if (y1 > by && y2 > by) return false
    if (x1 >= ax && x1 <= bx && y1 >= ay && y1 <= by) return true
    if (x2 >= ax && x2 <= bx && y2 >= ay && y2 <= by) return true
    return segVsSeg_(x1, y1, x2, y2, ax, ay, bx, ay) ||
           segVsSeg_(x1, y1, x2, y2, bx, ay, bx, by) ||
           segVsSeg_(x1, y1, x2, y2, bx, by, ax, by) ||
           segVsSeg_(x1, y1, x2, y2, ax, by, ax, ay)
  }

  segVsSeg_(ax, ay, bx, by, cx, cy, dx, dy) {
    var d = (bx - ax) * (dy - cy) - (by - ay) * (dx - cx)
    if (d == 0) return false
    var t = ((cx - ax) * (dy - cy) - (cy - ay) * (dx - cx)) / d
    var u = ((cx - ax) * (by - ay) - (cy - ay) * (bx - ax)) / d
    return t >= 0 && t <= 1 && u >= 0 && u <= 1
  }

  draw(g) {
    _renderer.beginFrame(_camera)
    var quad = _quad

    // Whole fruits.
    for (f in _fruits) {
      var p = _manifest["sprites"][f["name"]]["uv"]
      quad.uv(p[0], p[1], p[2], p[3])
      quad.width = 80
      quad.height = 80
      quad.x = f["x"]
      quad.y = f["y"]
      quad.setTint(1, 1, 1, 1)
      quad.draw(_renderer)
    }

    // Sliced halves — left and right cells. Real 2D rotation
    // around the half's centre via quad.rotation; left half spins
    // CCW, right half CW (sign of vrot set at slice time). Halves
    // fade out as age approaches 1s.
    for (h in _halves) {
      var key = h["name"] + "_" + h["side"]
      var p = _manifest["halves"][key]["uv"]
      quad.uv(p[0], p[1], p[2], p[3])
      quad.rotation = h["rot"]
      quad.width  = 40
      quad.height = 80
      quad.x = h["x"]
      quad.y = h["y"]
      var alpha = 1 - h["age"]
      if (alpha < 0) alpha = 0
      quad.setTint(1, 1, 1, alpha)
      quad.draw(_renderer)
    }

    // Reset rotation before drawing the rest of the frame — the
    // halves loop above leaves _quad with the last half's spin
    // angle, which would otherwise tumble the streak/HUD glyphs.
    quad.rotation = 0

    // Streak — sample the glow sprite along the trail, oldest points
    // most transparent. Ages run 0 (newest, just-added) up to ~16
    // (oldest, about to drop).
    var streakUv = _manifest["hud"]["streak"]["uv"]
    quad.uv(streakUv[0], streakUv[1], streakUv[2], streakUv[3])
    var ti = 0
    while (ti < _trail.count) {
      var p = _trail[ti]
      var a = p["age"] / 16
      var alpha = (1 - a) * (1 - a)
      quad.x = p["x"]
      quad.y = p["y"]
      quad.width  = 14 + 6 * (1 - a)
      quad.height = 14 + 6 * (1 - a)
      quad.setTint(1, 1, 0.85, alpha)
      quad.draw(_renderer)
      ti = ti + 1
    }

    // HUD — lives (hearts top-left).
    var heartUv = _manifest["hud"]["heart"]["uv"]
    quad.uv(heartUv[0], heartUv[1], heartUv[2], heartUv[3])
    quad.width  = 32
    quad.height = 32
    quad.setTint(1, 1, 1, 1)
    var hi = 0
    while (hi < _lives) {
      quad.x = 28 + hi * 36
      quad.y = 28
      quad.draw(_renderer)
      hi = hi + 1
    }

    // HUD — score (digits top-right). Right-aligned by precomputing
    // the total width.
    var digits = _score.toString
    var n = digits.count
    var startX = 640 - 16 - 24 * n + 12   // anchor=center → +half-width
    var di = 0
    while (di < n) {
      var ch = digits[di]
      var dproto = _manifest["hud"]["digits"][ch]
      quad.uv(dproto["uv"][0], dproto["uv"][1], dproto["uv"][2], dproto["uv"][3])
      quad.width  = 24
      quad.height = 24
      quad.x = startX + di * 24
      quad.y = 28
      quad.draw(_renderer)
      di = di + 1
    }

    if (_state == "gameover") drawGameOver_(heartUv)

    _renderer.flush(g.pass)
  }

  // "GAME OVER" overlay — extracted into a method so the tiered JIT
  // compiles it with its own profile.  Inline in draw() it kept the
  // rarely-taken branch un-profiled and hit a known mis-compile where
  // `quad` / `x0` were read from the wrong register on first entry.
  drawGameOver_(heartUv) {
    var pulse = 0.5 + 0.5 * (_gameoverT * 4).sin
    var alpha = 0.7 + 0.3 * pulse
    var quad = _quad
    // Stale-atlas fallback: if the cached atlas.json predates the
    // letter glyphs, render a pulsing heart instead.
    var letters = _manifest["hud"]["letters"]
    if (letters == null) {
      quad.uv(heartUv[0], heartUv[1], heartUv[2], heartUv[3])
      quad.width  = 96
      quad.height = 96
      quad.setTint(1, 0.35, 0.35, alpha)
      quad.x = 320
      quad.y = 240
      quad.draw(_renderer)
      return
    }
    var msg = "GAME OVER"
    var glyphW = 40
    var totalW = msg.count * glyphW
    var x0 = (640 - totalW) / 2 + glyphW / 2
    var k = 0
    while (k < msg.count) {
      var ch = msg[k]
      if (ch != " ") {
        var lproto = letters[ch]
        if (lproto != null) {
          quad.uv(lproto["uv"][0], lproto["uv"][1], lproto["uv"][2], lproto["uv"][3])
          quad.width  = 36
          quad.height = 48
          quad.x = x0 + k * glyphW
          quad.y = 220
          quad.setTint(1, 0.35, 0.35, alpha)
          quad.draw(_renderer)
        }
      }
      k = k + 1
    }

    // Hint line — same letter glyphs but smaller and dimmer so
    // the headline reads first. Animates in lockstep with pulse
    // so it feels alive while you decide.
    var hint = "CLICK TO RESUME"
    var hintW = 22
    var hintTotal = hint.count * hintW
    var hx0 = (640 - hintTotal) / 2 + hintW / 2
    var hk = 0
    while (hk < hint.count) {
      var hch = hint[hk]
      if (hch != " ") {
        var hproto = letters[hch]
        if (hproto != null) {
          quad.uv(hproto["uv"][0], hproto["uv"][1], hproto["uv"][2], hproto["uv"][3])
          quad.width  = 18
          quad.height = 24
          quad.x = hx0 + hk * hintW
          quad.y = 290
          quad.setTint(0.95, 0.85, 0.55, 0.6 + 0.4 * pulse)
          quad.draw(_renderer)
        }
      }
      hk = hk + 1
    }
  }
}

Game.run(FruitSlicer)

import "@hatch:assert" for Expect

// `Future`, `Browser`, `WebSocket`, `Dom`, `LocalStorage` are
// loaded by the runtime — no boilerplate needed. Async bridges
// resume through the scheduler in both modes; print *inside*
// the fiber so results land in the output pane.

var fiber = Fiber.new {
  System.print("before: %(Dom.text("#title").await)")
  Browser.setTimeout(0).await
  Dom.setText("#title", "rewritten by wren").await
  Dom.setText("#msg", "scheduler resumed me after 0ms").await
  Dom.addClass("#title", "dim").await
  System.print("done")
}
fiber.try()

// Recursive compute through the wasm tier-up JIT. fib(20) lands
// at ~3 ms post-warmup on both worker and main mode.
var start = System.clock
var fib
fib = Fn.new {|n| n < 2 ? n : fib.call(n - 1) + fib.call(n - 2) }
var result = fib.call(20)
var elapsed = (System.clock - start) * 1000

Expect.that(result).toBe(6765)
var hundredths = (elapsed * 100).round
var whole = (hundredths / 100).floor
var frac = hundredths - whole * 100
var fracStr = frac < 10 ? "0%(frac)" : "%(frac)"
System.print("fib(20) = %(result)  (%(whole).%(fracStr) ms)")

import "@hatch:math"   for Vec3, Mat4, Quat, Math
import "@hatch:assert" for Expect

// Helper — String interpolation of a Vec3 lands on the default
// "instance of Vec3" toString today, so we render fields by hand.
var fmt = Fn.new {|v| "(%(v.x), %(v.y), %(v.z))" }

var a = Vec3.new(1, 2, 3)
var b = Vec3.new(4, 5, 6)

System.print("a       = %(fmt.call(a))")
System.print("b       = %(fmt.call(b))")
System.print("a + b   = %(fmt.call(a + b))")
System.print("a · b   = %(a.dot(b))")
System.print("a × b   = %(fmt.call(a.cross(b)))")
System.print("|a|     = %(a.length)")

// Mat4.translation takes three components, not a Vec3.
var m = Mat4.translation(10, 0, 0)
var p = m.transformPoint(a)
System.print("translated a → %(fmt.call(p))")
Expect.that(p.x).toBe(11)

// Quaternion rotation 90° around Y.
var q = Quat.fromAxisAngle(Vec3.new(0, 1, 0), Math.radians(90))
var r = q.rotateVec3(Vec3.new(1, 0, 0))
// (1,0,0) rotated 90° around Y → (0, 0, -1) (within float epsilon).
System.print("rotated x-hat by 90°/Y → %(fmt.call(r))")
Expect.that(Math.approxEq(r.z, -1, 0.001)).toBe(true)
System.print("✓ all assertions pass")

import "@hatch:ecs"    for World
import "@hatch:assert" for Expect

class Position {
  construct new(x, y) {
    _x = x
    _y = y
  }
  x { _x }
  x=(v) { _x = v }
  y { _y }
  y=(v) { _y = v }
  toString { "(%(_x), %(_y))" }
}

class Velocity {
  construct new(x, y) {
    _x = x
    _y = y
  }
  x { _x }
  y { _y }
}

class Tag {
  construct new(name) {
    _name = name
  }
  name { _name }
}

var w = World.new()

// Spawn three entities, attach component bundles.
var alice = w.spawn()
w.attach(alice, Position.new(0, 0))
w.attach(alice, Velocity.new(1, 2))
w.attach(alice, Tag.new("alice"))

var bob = w.spawn()
w.attach(bob, Position.new(10, 5))
w.attach(bob, Velocity.new(-1, 0))
w.attach(bob, Tag.new("bob"))

// Static entity — no Velocity component.
var rock = w.spawn()
w.attach(rock, Position.new(50, 50))
w.attach(rock, Tag.new("rock"))

System.print("world has %(w.count) entities")
Expect.that(w.count).toBe(3)

// Fluent query builder is reached via World.query (not Query.new).
// .iterate runs the filter and returns an iterable; for-in does
// the rest.
for (e in w.query.with(Position).with(Velocity).iterate) {
  var p = w.get(e, Position)
  var v = w.get(e, Velocity)
  p.x = p.x + v.x
  p.y = p.y + v.y
}

for (e in w.query.with(Position).with(Tag).iterate) {
  var name = w.get(e, Tag).name
  var p    = w.get(e, Position)
  System.print("  %(name): %(p)")
}

Expect.that(w.get(alice, Position).x).toBe(1)
Expect.that(w.get(rock, Position).x).toBe(50)  // no velocity → static
System.print("✓ motion + static both as expected")

import "@hatch:game" for Game
import "@hatch:gpu"  for Renderer2D, Camera2D, Sprite

class SpriteGrid is Game {
  construct new() {}

  config { {
    "title":      "Sprite Grid",
    "width":      640,
    "height":     480,
    "clearColor": [0.04, 0.05, 0.08, 1.0],
    // Web-only: attach to the existing <canvas> in the playground
    // stage instead of spawning a fresh one. Ignored on native.
    "canvas":     "stage-canvas"
  } }

  setup(g) {
    _renderer = Renderer2D.new(g.device, g.surfaceFormat)
    _camera   = Camera2D.contain(640, 480, g.width, g.height)

    // Solid-white 8×8 atlas built byte-by-byte. Sidesteps
    // `@hatch:image` (which has no web cdylib today). Sprites
    // tint the atlas via vertex colour, so a single texture
    // backs the whole rainbow grid.
    var w = 8
    var h = 8
    var bytes = ""
    var i = 0
    while (i < w * h * 4) {
      bytes = bytes + String.fromCodePoint(255)
      i = i + 1
    }
    _texture = g.device.createTexture({
      "width":  w, "height": h,
      "format": "rgba8unorm",
      "usage":  ["texture-binding", "copy-dst"]
    })
    g.device.writeTexture(_texture, bytes, {
      "width": w, "height": h, "bytesPerRow": w * 4
    })

    _cols = 18
    _rows = 14
    _cell = 28
    _offsetX = 0
    _offsetY = 0

    // Pre-build sprites once; positions + tints update each frame.
    _sprites = []
    var r = 0
    while (r < _rows) {
      var c = 0
      while (c < _cols) {
        var s = Sprite.new(_texture)
        s.width  = _cell - 4
        s.height = _cell - 4
        s.anchor(0.5, 0.5)
        _sprites.add(s)
        c = c + 1
      }
      r = r + 1
    }
  }

  resize(g, w, h) { _camera.fitContain(w, h) }

  update(g) {
    if (g.input.justPressed("Escape")) g.requestQuit
    var speed = 200 * g.dt
    if (g.input.isDown("KeyA") || g.input.isDown("ArrowLeft"))  _offsetX = _offsetX - speed
    if (g.input.isDown("KeyD") || g.input.isDown("ArrowRight")) _offsetX = _offsetX + speed
    if (g.input.isDown("KeyW") || g.input.isDown("ArrowUp"))    _offsetY = _offsetY - speed
    if (g.input.isDown("KeyS") || g.input.isDown("ArrowDown"))  _offsetY = _offsetY + speed
  }

  draw(g) {
    _renderer.beginFrame(_camera)
    var t = g.elapsed
    var originX = (_camera.width  - _cols * _cell) / 2 + _offsetX
    var originY = (_camera.height - _rows * _cell) / 2 + _offsetY
    var idx = 0
    var r = 0
    while (r < _rows) {
      var c = 0
      while (c < _cols) {
        var s = _sprites[idx]
        s.x = originX + c * _cell + _cell / 2
        s.y = originY + r * _cell + _cell / 2
        var phase = (c + r) * 0.25 + t * 1.5
        s.setTint(
          0.5 + 0.5 * phase.sin,
          0.5 + 0.5 * (phase + 2.094).sin,
          0.5 + 0.5 * (phase + 4.188).sin,
          1.0
        )
        s.draw(_renderer)
        idx = idx + 1
        c = c + 1
      }
      r = r + 1
    }
    _renderer.flush(g.pass)
  }
}

Game.run(SpriteGrid)

import "@hatch:window" for Window
import "@hatch:gpu"    for Gpu, Camera2D, Renderer2D

var SURF_W = 600
var SURF_H = 400

// BYO canvas — same shape main + worker honour. The page already
// owns <canvas id="stage-canvas">; `Window.create({"canvas": <id>})`
// attaches without touching the DOM, so this works in worker mode
// (where the canvas arrives via `transferControlToOffscreen`).
var window = Window.create({
  "canvas": "stage-canvas",
  "title":  "renderer2d demo"
})

var device  = Gpu.requestDevice({})
var surface = device.createSurface(window.handle)
var renderer = Renderer2D.new(device, "preferred")

// 4x4 RGBA8 white texture — sprites tint it via vertex colour
// so we don't need any image asset.
var whiteBytes = ""
var i = 0
while (i < 4 * 4 * 4) {
  whiteBytes = whiteBytes + String.fromCodePoint(255)
  i = i + 1
}
var atlas = device.createTexture({
  "width":  4, "height": 4,
  "format": "rgba8unorm",
  "usage":  ["texture-binding", "copy-dst"]
})
device.writeTexture(atlas, whiteBytes, {
  "width": 4, "height": 4, "bytesPerRow": 16
})

var camera = Camera2D.contain(SURF_W, SURF_H, SURF_W, SURF_H)
renderer.beginFrame(camera)

// 4×4 grid, four-colour rotation.
var palette = [
  [0.85, 0.48, 0.17, 1.0],
  [0.36, 0.78, 0.50, 1.0],
  [0.32, 0.55, 0.91, 1.0],
  [0.93, 0.84, 0.36, 1.0],
]
var size   = 80
var gap    = 12
var totalW = 4 * size + 3 * gap
var totalH = 4 * size + 3 * gap
var ox = (SURF_W - totalW) / 2
var oy = (SURF_H - totalH) / 2
var cell = 0
while (cell < 16) {
  var col = cell % 4
  var row = (cell / 4).floor
  var x = ox + col * (size + gap)
  var y = oy + row * (size + gap)
  var c = palette[(row + col) % 4]
  renderer.drawSpriteTinted(atlas, x, y, size, size, c[0], c[1], c[2], c[3])
  cell = cell + 1
}

var frame = surface.acquire()
var enc   = device.createCommandEncoder()
var pass  = enc.beginRenderPass({
  "colorAttachments": [{
    "view":       frame.view,
    "loadOp":     "clear",
    "clearValue": { "r": 0.06, "g": 0.05, "b": 0.04, "a": 1.0 },
    "storeOp":    "store"
  }]
})
renderer.flush(pass)
pass.end
enc.finish
device.submit([enc])
frame.present
System.print("rendered ✓ (4×4 grid)")
